// --- types.d.ts ---
export interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

export interface WeatherCardProps {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit?: 'C' | 'F' | string;
  forecast: ForecastDay[];
}

export interface FormattedForecast extends ForecastDay {
  formattedHigh: string;
  formattedLow: string;
}

export interface WeatherCardHookReturn {
  formattedTemp: string;
  displayUnit: string;
  conditionIcon: string;
  formattedForecast: FormattedForecast[];
  accessibilityLabel: string;
}

export interface WeatherHeaderProps {
  city: string;
  condition: string;
}

export interface CurrentDisplayProps {
  temp: string;
  icon: string;
  condition: string;
}

export interface WeatherDetailsProps {
  humidity: number;
  windSpeed: number;
}

export interface ForecastStripProps {
  days: FormattedForecast[];
}

export interface ForecastItemProps {
  day: FormattedForecast;
}


// --- constants.ts ---
// constants.ts — static data, mappings, configurations

export const CONDITION_ICONS: Record<string, string> = {
  'Sunny': '☀️',
  'Clear': '☀️',
  'Cloudy': '☁️',
  'Partly Cloudy': '⛅',
  'Rain': '🌧️',
  'Showers': '🌦️',
  'Thunderstorm': '⛈️',
  'Snow': '❄️',
  'Mist': '🌫️',
  'Fog': '🌫️',
  'Default': '🌡️',
};

export const DEFAULT_UNIT = 'C';

export const UNIT_LABELS: Record<string, string> = {
  'C': '°C',
  'F': '°F',
};

export const TEMP_FORMAT_CONFIG = {
  decimalPlaces: 0,
};

/**
 * Generates an accessibility label for the weather card.
 * @param city The name of the city
 * @param condition The weather condition description
 * @param temperature The formatted temperature value
 * @param unitLabel The unit label (e.g., °C or °F)
 * @returns A descriptive string for screen readers
 */
export const getAccessibilityLabel = (
  city: string,
  condition: string,
  temperature: string | number,
  unitLabel: string
): string => {
  return `Current weather in ${city}: ${condition}, ${temperature}${unitLabel}.`;
};


// --- hooks.ts ---
import { useMemo } from 'react';
import type { WeatherCardProps, WeatherCardHookReturn, FormattedForecast } from './types';

/**
 * Hook to process weather data for display in the WeatherCard component.
 */
export function useWeatherCard(props: WeatherCardProps): WeatherCardHookReturn {
  const {
    city,
    temperature,
    condition,
    humidity,
    windSpeed,
    unit = 'C',
    forecast,
  } = props;

  // Determine the display unit symbol
  const displayUnit = useMemo(() => {
    return unit === 'F' ? '°F' : '°C';
  }, [unit]);

  // Format the current temperature with unit
  const formattedTemp = `${temperature}${displayUnit}`;

  // Map condition strings to icons/emojis
  const conditionIcon = useMemo(() => {
    const lowerCondition = condition.toLowerCase();
    if (lowerCondition.includes('sunny') || lowerCondition.includes('clear')) {
      return '☀️';
    }
    if (lowerCondition.includes('cloudy')) {
      return '☁️';
    }
    if (lowerCondition.includes('rainy') || lowerCondition.includes('rain')) {
      return '🌧️';
    }
    if (lowerCondition.includes('snowy') || lowerCondition.includes('snow')) {
      return '❄️';
    }
    if (lowerCondition.includes('stormy') || lowerCondition.includes('storm')) {
      return '⛈️';
    }
    return '❓';
  }, [condition]);

  // Transform forecast data with formatted high/low strings
  const formattedForecast: FormattedForecast[] = useMemo(() => {
    return forecast.map((item) => ({
      ...item,
      formattedHigh: `${item.high}${displayUnit}`,
      formattedLow: `${item.low}${displayUnit}`,
    }));
  }, [forecast, displayUnit]);

  // Construct accessibility label for screen readers
  const accessibilityLabel = useMemo(() => {
    return `Current weather in ${city}: ${temperature} degrees ${unit}, ${condition}. Humidity: ${humidity}%, Wind speed: ${windSpeed} units.`;
  }, [city, temperature, unit, condition, humidity, windSpeed]);

  return {
    formattedTemp,
    displayUnit,
    conditionIcon,
    formattedForecast,
    accessibilityLabel,
  };
}


// --- components/WeatherHeader.tsx ---
import React from 'react';
import { Stack, Heading, Text } from '@ggui-ai/design/primitives';
import { WeatherHeaderProps } from '../types';

/**
 * WeatherHeader component displays the location and current weather summary.
 * It provides a clear visual hierarchy using semantic tokens and heading levels.
 */
export const WeatherHeader: React.FC<WeatherHeaderProps> = ({ city, condition }) => {
  return (
    <Stack gap={4}>
      <Heading 
        level={2} 
        color="var(--ggui-color-onSurface)"
      >
        {city}
      </Heading>
      <Text 
        size="sm" 
        color="var(--ggui-color-onSurfaceVariant)"
      >
        {condition}
      </Text>
    </Stack>
  );
};


// --- components/CurrentDisplay.tsx ---
import React from 'react';
import { Stack, Text } from '@ggui-ai/design/primitives';
import { CurrentDisplayProps } from '../types';

/**
 * Component to display the current weather conditions, including icon, temperature, and condition text.
 */
export const CurrentDisplay: React.FC<CurrentDisplayProps> = ({
  temp,
  icon,
  condition,
}) => {
  return (
    <Stack gap={4} align="center">
      {/* Group icon and temperature horizontally */}
      <Stack direction="horizontal" align="center" gap={12}>
        <span
          aria-hidden="true"
          style={{
            fontSize: 64,
            lineHeight: 1,
            display: 'inline-block',
          }}
        >
          {icon}
        </span>
        <Text
          style={{
            fontSize: 64,
            fontWeight: 700,
            color: 'var(--ggui-color-onSurface)',
            lineHeight: 1,
          }}
        >
          {temp}
        </Text>
      </Stack>

      {/* Weather condition text */}
      <Text
        style={{
          fontSize: 20,
          fontWeight: 500,
          color: 'var(--ggui-color-onSurfaceVariant)',
        }}
      >
        {condition}
      </Text>
    </Stack>
  );
};


// --- components/WeatherDetails.tsx ---
import React from 'react';
import { Grid, Stack, Text } from '@ggui-ai/design/primitives';
import { WeatherDetailsProps } from '../types';

export const WeatherDetails: React.FC<WeatherDetailsProps> = ({ humidity, windSpeed }) => {
  return (
    <Grid
      columns={2}
      gap={16}
      style={{
        width: '100%',
        paddingTop: 'var(--ggui-spacing-4, 16px)',
        borderTop: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
      }}
    >
      <Stack gap={4} align="start">
        <Stack direction="horizontal" gap={4} align="center" aria-hidden="true">
          <Text as="span" size="sm">💧</Text>
          <Text size="sm" color="var(--ggui-color-onSurfaceVariant)">
            Humidity
          </Text>
        </Stack>
        <Text
          variant="body"
          weight="bold"
          color="var(--ggui-color-onSurface)"
          aria-label={`Humidity ${humidity} percent`}
        >
          {humidity}%
        </Text>
      </Stack>

      <Stack gap={4} align="start">
        <Stack direction="horizontal" gap={4} align="center" aria-hidden="true">
          <Text as="span" size="sm">🌬️</Text>
          <Text size="sm" color="var(--ggui-color-onSurfaceVariant)">
            Wind Speed
          </Text>
        </Stack>
        <Text
          variant="body"
          weight="bold"
          color="var(--ggui-color-onSurface)"
          aria-label={`Wind speed ${windSpeed} kilometers per hour`}
        >
          {windSpeed} km/h
        </Text>
      </Stack>
    </Grid>
  );
};


// --- components/ForecastStrip.tsx ---
import React from 'react';
import { Stack, Text } from '@ggui-ai/design/primitives';
import { ForecastStripProps, ForecastItemProps } from '../types';

/**
 * Internal component for rendering a single day's forecast.
 */
const ForecastItem: React.FC<ForecastItemProps> = ({ day }) => {
  return (
    <Stack align="center" gap={4}>
      <Text
        size="xs"
        variant="label"
        color="var(--ggui-color-onSurfaceVariant)"
      >
        {day.day}
      </Text>
      <div 
        style={{ 
          fontSize: '24px', 
          lineHeight: 1,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          height: '24px'
        }}
      >
        {day.icon}
      </div>
      <Text 
        weight="bold"
        color="var(--ggui-color-onSurface)"
      >
        {day.formattedHigh}
      </Text>
      <Text
        variant="bodySmall"
        color="var(--ggui-color-onSurfaceVariant)"
      >
        {day.formattedLow}
      </Text>
    </Stack>
  );
};

/**
 * ForecastStrip displays a horizontal row of forecast items.
 */
export const ForecastStrip: React.FC<ForecastStripProps> = ({ days }) => {
  return (
    <section
      aria-label="5-day forecast"
      style={{
        width: '100%',
        borderTop: '1px solid var(--ggui-color-outlineVariant)',
        paddingTop: '16px',
      }}
    >
      <Stack 
        direction="horizontal" 
        justify="between" 
        align="center"
        gap={0}
      >
        {days.map((item) => (
          <ForecastItem key={item.day} day={item} />
        ))}
      </Stack>
    </section>
  );
};


// --- ui.tsx ---
import React from 'react';
import { WeatherCardProps } from './types';
import { useWeatherCard } from './hooks';
import { WeatherHeader, CurrentDisplay, WeatherDetails, ForecastStrip } from './components';
import { Container, Card, Stack, Divider } from '@ggui-ai/design/primitives';

export const WeatherCard: React.FC<WeatherCardProps> = (props) => {
  const { city, condition, humidity, windSpeed } = props;
  const {
    formattedTemp,
    displayUnit,
    conditionIcon,
    formattedForecast,
    accessibilityLabel,
  } = useWeatherCard(props);

  return (
    <Container maxWidth="sm">
      <Card padding={24} shadow="md" aria-label={accessibilityLabel}>
        <Stack direction="vertical" gap={24}>
          <WeatherHeader city={city} condition={condition} />

          <CurrentDisplay 
            temp={formattedTemp} 
            icon={conditionIcon} 
            condition={condition} 
          />

          <WeatherDetails 
            humidity={humidity} 
            windSpeed={windSpeed} 
          />

          <Divider />

          <ForecastStrip days={formattedForecast} />
        </Stack>
      </Card>
    </Container>
  );
};

export default WeatherCard;


// --- render.tsx ---
// render.tsx — entry point
import React from 'react';
import type { Props } from './types';
import { useComponent } from './hooks';
import { ComponentUI } from './ui';

export default function Component(props: Props) {
  const state = useComponent(props);
  return <ComponentUI {...props} {...state} />;
}
